312	            if (hasQueryParam(uriInfo, "tagging")) {
313	                return handlePutObjectTagging(bucket, key, body);
314	            }
315	            if (hasQueryParam(uriInfo, "retention")) {
316	                return handlePutObjectRetention(bucket, key,
317	                        uriInfo.getQueryParameters().getFirst("versionId"), httpHeaders, body);
318	            }
319	            if (hasQueryParam(uriInfo, "legal-hold")) {
320	                return handlePutObjectLegalHold(bucket, key,
321	                        uriInfo.getQueryParameters().getFirst("versionId"), body);
322	            }
323	            if (hasQueryParam(uriInfo, "acl")) {
324	                s3Service.putObjectAcl(bucket, key, uriInfo.getQueryParameters().getFirst("versionId"),
325	                        new String(body, StandardCharsets.UTF_8));
326	                return Response.ok().build();
327	            }
328	
329	            if (uploadId != null && partNumber != null) {
330	                byte[] partData = decodeAwsChunked(body, contentEncoding, contentSha256);
331	                validateChecksumHeaders(httpHeaders, partData);
332	                String eTag = s3Service.uploadPart(bucket, key, uploadId, partNumber, partData);
333	                return Response.ok().header("ETag", eTag).build();
334	            }
335	
336	            if (copySource != null && !copySource.isEmpty()) {
337	                return handleCopyObject(copySource, bucket, key, contentType, httpHeaders);
338	            }
339	
340	            String lockMode = httpHeaders.getHeaderString("x-amz-object-lock-mode");
341	            String retainUntilStr = httpHeaders.getHeaderString("x-amz-object-lock-retain-until-date");
342	            String legalHold = httpHeaders.getHeaderString("x-amz-object-lock-legal-hold");
343	            Instant retainUntil = retainUntilStr != null ? Instant.parse(retainUntilStr) : null;
344	
345	            byte[] data = decodeAwsChunked(body, contentEncoding, contentSha256);
346	            validateChecksumHeaders(httpHeaders, data);
347	            String persistedEncoding = toPersistedContentEncoding(contentEncoding);
348	            S3Object obj = s3Service.putObject(bucket, key, data, contentType, extractUserMetadata(httpHeaders),
349	                    httpHeaders.getHeaderString("x-amz-storage-class"),
350	                    persistedEncoding,
351	                    lockMode, retainUntil, legalHold);
352	            var resp = Response.ok().header("ETag", obj.getETag());
353	            if (obj.getVersionId() != null) {
354	                resp.header("x-amz-version-id", obj.getVersionId());
355	            }
356	            appendObjectHeaders(resp, obj);
357	            return resp.build();
358	        } catch (AwsException e) {
359	            return xmlErrorResponse(e);
360	        }
361	    }
