363	    @GET
364	    @Path("/{bucket}/{key:.+}")
365	    public Response getObject(@PathParam("bucket") String bucket,
366	                              @PathParam("key") String key,
367	                              @QueryParam("versionId") String versionId,
368	                              @HeaderParam("x-amz-object-attributes") String objectAttributesHeader,
369	                              @HeaderParam("x-amz-max-parts") Integer maxParts,
370	                              @HeaderParam("x-amz-part-number-marker") Integer partNumberMarker,
371	                              @HeaderParam("If-Match") String ifMatch,
372	                              @HeaderParam("If-None-Match") String ifNoneMatch,
373	                              @HeaderParam("If-Modified-Since") String ifModifiedSince,
374	                              @HeaderParam("If-Unmodified-Since") String ifUnmodifiedSince,
375	                              @HeaderParam("Range") String rangeHeader,
376	                              @Context UriInfo uriInfo,
377	                              @Context HttpHeaders httpHeaders) {
378	        try {
379	            if (hasQueryParam(uriInfo, "tagging")) {
380	                return handleGetObjectTagging(bucket, key);
381	            }
382	            if (hasQueryParam(uriInfo, "retention")) {
383	                return handleGetObjectRetention(bucket, key, versionId);
384	            }
385	            if (hasQueryParam(uriInfo, "legal-hold")) {
386	                return handleGetObjectLegalHold(bucket, key, versionId);
387	            }
388	            if (hasQueryParam(uriInfo, "acl")) {
389	                return Response.ok(s3Service.getObjectAcl(bucket, key, versionId)).build();
390	            }
391	            if (hasQueryParam(uriInfo, "attributes")) {
392	                // Merge all x-amz-object-attributes header values (SDK may send multiple lines)
393	                List<String> attrHeaders = httpHeaders.getRequestHeader("x-amz-object-attributes");
394	                String mergedAttributes = attrHeaders != null ? String.join(",", attrHeaders) : objectAttributesHeader;
395	                return handleGetObjectAttributes(bucket, key, versionId,
396	                        mergedAttributes, maxParts, partNumberMarker);
397	            }
398	            if (hasPreconditions(ifMatch, ifNoneMatch, ifModifiedSince, ifUnmodifiedSince)) {
399	                // Fetch metadata only to evaluate preconditions, avoiding loading the full object unnecessarily.
400	                S3Object metadata = s3Service.headObject(bucket, key, versionId);
401	                Response preconditionResponse = checkPreconditions(metadata, ifMatch, ifNoneMatch, ifModifiedSince, ifUnmodifiedSince);
402	                if (preconditionResponse != null) {
403	                    return preconditionResponse;
404	                }
405	            }
406	            S3Object obj = s3Service.getObject(bucket, key, versionId);
407	
408	            if (rangeHeader != null && rangeHeader.startsWith("bytes=")) {
409	                return handleRangeRequest(obj, rangeHeader);
410	            }
411	
412	            var resp = Response.ok(obj.getData())
413	                    .header("Content-Type", obj.getContentType())
414	                    .header("Content-Length", obj.getSize())
415	                    .header("ETag", obj.getETag())
416	                    .header("Last-Modified", RFC_822.format(obj.getLastModified()))
417	                    .header("Accept-Ranges", "bytes");
418	            if (obj.getVersionId() != null) {
419	                resp.header("x-amz-version-id", obj.getVersionId());
420	            }
421	            appendObjectHeaders(resp, obj);
422	            return resp.build();
423	        } catch (AwsException e) {
424	            return xmlErrorResponse(e);
425	        }
426	    }
