428	    private Response handleRangeRequest(S3Object obj, String rangeHeader) {
429	        byte[] data = obj.getData();
430	        int totalSize = data.length;
431	        String rangeSpec = rangeHeader.substring("bytes=".length()).trim();
432	
433	        int start, end;
434	        try {
435	            int dash = rangeSpec.indexOf('-');
436	            if (dash < 0) {
437	                return invalidRangeResponse(totalSize);
438	            }
439	            String before = rangeSpec.substring(0, dash);
440	            String after = rangeSpec.substring(dash + 1);
441	            if (before.isEmpty() && after.isEmpty()) {
442	                return invalidRangeResponse(totalSize);
443	            }
444	            if (before.isEmpty()) {
445	                int suffix = Integer.parseInt(after);
446	                if (suffix <= 0) {
447	                    return invalidRangeResponse(totalSize);
448	                }
449	                start = Math.max(0, totalSize - suffix);
450	                end = totalSize - 1;
451	            } else {
452	                start = Integer.parseInt(before);
453	                end = after.isEmpty() ? totalSize - 1 : Math.min(Integer.parseInt(after), totalSize - 1);
454	            }
455	        } catch (NumberFormatException e) {
456	            return invalidRangeResponse(totalSize);
457	        }
458	
459	        if (start < 0 || start >= totalSize || start > end) {
460	            return invalidRangeResponse(totalSize);
461	        }
462	
463	        byte[] rangeData = java.util.Arrays.copyOfRange(data, start, end + 1);
464	        return Response.status(206)
465	                .entity(rangeData)
466	                .header("Content-Type", obj.getContentType())
467	                .header("Content-Length", rangeData.length)
468	                .header("Content-Range", "bytes " + start + "-" + end + "/" + totalSize)
469	                .header("ETag", obj.getETag())
470	                .header("Last-Modified", RFC_822.format(obj.getLastModified()))
471	                .header("Accept-Ranges", "bytes")
472	                .build();
473	    }
474	
475	    private Response invalidRangeResponse(int totalSize) {
476	        String xml = new XmlBuilder()
477	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
478	                .start("Error")
479	                .elem("Code", "InvalidRange")
480	                .elem("Message", "The requested range is not satisfiable.")
481	                .elem("RequestId", java.util.UUID.randomUUID().toString())
482	                .end("Error")
483	                .build();
484	        return Response.status(416)
485	                .entity(xml)
486	                .type(MediaType.APPLICATION_XML)
487	                .header("Content-Range", "bytes */" + totalSize)
488	                .build();
489	    }
