579	    public Response handleMultipartPost(@PathParam("bucket") String bucket,
580	                                         @PathParam("key") String key,
581	                                         @QueryParam("uploadId") String uploadId,
582	                                         @QueryParam("versionId") String versionId,
583	                                         @HeaderParam("Content-Type") String contentType,
584	                                         @Context HttpHeaders httpHeaders,
585	                                         @Context UriInfo uriInfo,
586	                                         byte[] body) {
587	        try {
588	            if (hasQueryParam(uriInfo, "uploads")) {
589	                MultipartUpload upload = s3Service.initiateMultipartUpload(bucket, key, contentType,
590	                        extractUserMetadata(httpHeaders), httpHeaders.getHeaderString("x-amz-storage-class"));
591	                String xml = new XmlBuilder()
592	                        .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
593	                        .start("InitiateMultipartUploadResult", AwsNamespaces.S3)
594	                        .elem("Bucket", bucket)
595	                        .elem("Key", key)
596	                        .elem("UploadId", upload.getUploadId())
597	                        .end("InitiateMultipartUploadResult")
598	                        .build();
599	                return Response.ok(xml).build();
600	            }
601	
602	            if (hasQueryParam(uriInfo, "restore")) {
603	                s3Service.restoreObject(bucket, key, versionId, new String(body, StandardCharsets.UTF_8));
604	                return Response.accepted().build();
605	            }
606	
607	            if (hasQueryParam(uriInfo, "select")) {
608	                S3Object obj = s3Service.getObject(bucket, key, versionId);
609	                byte[] result = s3SelectService.select(obj, new String(body, StandardCharsets.UTF_8));
610	                return Response.ok(result)
611	                        .type("application/octet-stream")
612	                        .build();
613	            }
614	
615	            if (uploadId != null) {
616	                List<Integer> partNumbers = parseCompleteMultipartBody(new String(body));
617	                S3Object obj = s3Service.completeMultipartUpload(bucket, key, uploadId, partNumbers);
618	                String baseUrl = uriInfo.getBaseUri().toString();
619	                if (baseUrl.endsWith("/")) {
620	                    baseUrl = baseUrl.substring(0, baseUrl.length() - 1);
621	                }
622	                XmlBuilder xmlBuilder = new XmlBuilder()
623	                        .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
624	                        .start("CompleteMultipartUploadResult", AwsNamespaces.S3)
625	                        .elem("Location", baseUrl + "/" + bucket + "/" + key)
626	                        .elem("Bucket", bucket)
627	                        .elem("Key", key)
628	                        .elem("ETag", obj.getETag());
629	                if (obj.getVersionId() != null) {
630	                    xmlBuilder.elem("VersionId", obj.getVersionId());
631	                }
632	                String xml = xmlBuilder.end("CompleteMultipartUploadResult").build();
633	                var resp = Response.ok(xml);
634	                if (obj.getVersionId() != null) {
635	                    resp.header("x-amz-version-id", obj.getVersionId());
636	                }
637	                return resp.build();
638	            }
639	
640	            return xmlErrorResponse(new AwsException("InvalidArgument",
641	                    "POST requires either ?uploads, ?uploadId, ?restore or ?select parameter.", 400));
642	        } catch (AwsException e) {
