828	    /**
829	     * Strips the {@code aws-chunked} token from a {@code Content-Encoding} value before persisting it.
830	     * {@code aws-chunked} is a transfer-protocol marker used by AWS SDK v2 streaming uploads and is not
831	     * a real content encoding. For example, {@code gzip,aws-chunked} persists as {@code gzip};
832	     * a value of only {@code aws-chunked} persists as {@code null}.
833	     */
834	    private static String toPersistedContentEncoding(String contentEncoding) {
835	        if (contentEncoding == null) {
836	            return null;
837	        }
838	        String[] tokens = contentEncoding.split(",");
839	        StringBuilder result = new StringBuilder();
840	        for (String token : tokens) {
841	            String trimmed = token.trim();
842	            if (!trimmed.equalsIgnoreCase("aws-chunked")) {
843	                if (!result.isEmpty()) {
844	                    result.append(",");
845	                }
846	                result.append(trimmed);
847	            }
848	        }
849	        return result.isEmpty() ? null : result.toString();
850	    }
