852	    // --- AWS Chunked Decoding ---
853	
854	    /**
855	     * Decodes aws-chunked transfer encoding used by AWS SDK v2 with SigV4 chunk signing.
856	     * Format: hex-size;chunk-signature=sig\r\n data \r\n ... 0;chunk-signature=sig\r\n
857	     */
858	    private byte[] decodeAwsChunked(byte[] body, String contentEncoding, String contentSha256) {
859	        boolean isAwsChunked = (contentEncoding != null && contentEncoding.contains("aws-chunked"))
860	                || "STREAMING-AWS4-HMAC-SHA256-PAYLOAD".equals(contentSha256)
861	                || "STREAMING-AWS4-HMAC-SHA256-PAYLOAD-TRAILER".equals(contentSha256);
862	        if (!isAwsChunked) {
863	            return body;
864	        }
865	
866	        try {
867	            ByteArrayOutputStream out = new ByteArrayOutputStream();
868	            String raw = new String(body, StandardCharsets.ISO_8859_1);
869	            int pos = 0;
870	            while (pos < raw.length()) {
871	                int lineEnd = raw.indexOf('\n', pos);
872	                if (lineEnd < 0) break;
873	                String line = raw.substring(pos, lineEnd).trim();
874	                int semiColon = line.indexOf(';');
875	                String hexSize = semiColon >= 0 ? line.substring(0, semiColon) : line;
876	                int chunkSize = Integer.parseInt(hexSize.trim(), 16);
877	                if (chunkSize == 0) break;
878	
879	                int dataStart = lineEnd + 1;
880	                byte[] chunkData = new byte[chunkSize];
881	                System.arraycopy(body, dataStart, chunkData, 0, chunkSize);
882	                out.write(chunkData);
883	
884	                pos = dataStart + chunkSize;
885	                if (pos < raw.length() && raw.charAt(pos) == '\r') pos++;
886	                if (pos < raw.length() && raw.charAt(pos) == '\n') pos++;
887	            }
888	            return out.toByteArray();
889	        } catch (Exception e) {
890	            LOG.debugv("Failed to decode aws-chunked body, using raw: {0}", e.getMessage());
891	            return body;
892	        }
893	    }
