1391	    private void validateContentLengthRange(String policyBase64, int contentLength) {
1392	        try {
1393	            String decoded = new String(java.util.Base64.getDecoder().decode(policyBase64), StandardCharsets.UTF_8);
1394	            // Parse conditions array from the policy JSON to find content-length-range
1395	            int condIdx = decoded.indexOf("\"conditions\"");
1396	            if (condIdx < 0) {
1397	                return;
1398	            }
1399	            // Look for content-length-range condition: ["content-length-range", min, max]
1400	            String lower = decoded.toLowerCase(Locale.ROOT);
1401	            int rangeIdx = lower.indexOf("content-length-range");
1402	            if (rangeIdx < 0) {
1403	                return;
1404	            }
1405	            // Find the enclosing array bracket
1406	            int bracketStart = decoded.lastIndexOf('[', rangeIdx);
1407	            int bracketEnd = decoded.indexOf(']', rangeIdx);
1408	            if (bracketStart < 0 || bracketEnd < 0) {
1409	                return;
1410	            }
1411	            String rangeArray = decoded.substring(bracketStart, bracketEnd + 1);
1412	            // Extract min and max values
1413	            String[] tokens = rangeArray.replaceAll("[\\[\\]\"]", "").split(",");
1414	            if (tokens.length >= 3) {
1415	                long min = Long.parseLong(tokens[1].trim());
1416	                long max = Long.parseLong(tokens[2].trim());
1417	                if (contentLength < min || contentLength > max) {
1418	                    throw new AwsException("EntityTooLarge",
1419	                            "Your proposed upload exceeds the maximum allowed size.", 400);
1420	                }
