1435	            String trimmed = part.trim();
1436	            if (trimmed.toLowerCase(Locale.ROOT).startsWith("boundary=")) {
1437	                String boundary = trimmed.substring("boundary=".length()).trim();
1438	                if (boundary.startsWith("\"") && boundary.endsWith("\"")) {
1439	                    boundary = boundary.substring(1, boundary.length() - 1);
1440	                }
