1447	    private static List<byte[]> splitMultipartParts(byte[] body, byte[] boundary) {
1448	        java.util.ArrayList<byte[]> parts = new java.util.ArrayList<>();
1449	        int pos = indexOf(body, boundary, 0);
1450	        if (pos < 0) {
1451	            return parts;
1452	        }
1453	        // Skip past the first boundary line
1454	        pos += boundary.length;
1455	        // Skip the CRLF or -- after boundary
1456	        if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
1457	            return parts; // closing boundary immediately
1458	        }
1459	        if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
1460	            pos += 2;
1461	        }
1462	
1463	        while (pos < body.length) {
1464	            int nextBoundary = indexOf(body, boundary, pos);
1465	            if (nextBoundary < 0) {
1466	                break;
1467	            }
1468	            parts.add(Arrays.copyOfRange(body, pos, nextBoundary));
1469	            pos = nextBoundary + boundary.length;
1470	            // Check for closing boundary --
1471	            if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
1472	                break;
1473	            }
1474	            // Skip CRLF after boundary
1475	            if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
1476	                pos += 2;
1477	            }
1478	        }
1479	        return parts;
1480	    }
