1511	        int valueStart = idx + lowerName.length();
1512	        int lineEnd = headers.indexOf('\r', valueStart);
1513	        if (lineEnd < 0) {
1514	            lineEnd = headers.indexOf('\n', valueStart);
1515	        }
1516	        if (lineEnd < 0) {
1517	            lineEnd = headers.length();
1518	        }
