1532	        if (disposition.charAt(valueStart) == '"') {
1533	            valueStart++;
1534	            int valueEnd = disposition.indexOf('"', valueStart);
1535	            if (valueEnd < 0) {
1536	                return disposition.substring(valueStart);
1537	            }
1538	            return disposition.substring(valueStart, valueEnd);
